import { execution } from '@dynatrace-sdk/automation-utils';

export default async function ({ execution_id }) {
  const exec = await execution(execution_id);
  const lookup = await exec.result('lookup_remediation');

  if (!lookup.records || lookup.records.length === 0) {
    console.log('No remediation.url found for the affected service \u2014 skipping.');
    return { skipped: true, reason: 'no-remediation-url' };
  }

  const record = lookup.records[0];
  const url = record['lookup.remediation.url'];
  const eventType = record['lookup.remediation.event_type'];

  console.log(`Triggering Gitea dispatch: url=${url} event_type=${eventType}`);

  const response = await fetch(url, {
    method: 'POST',
    headers: {
      'Accept': 'application/json',
      'Content-Type': 'application/json',
      'Authorization': 'token {{ env.GITEA_PAT }}'
    },
    body: JSON.stringify({ event_type: eventType })
  });

  const text = await response.text();
  console.log(`Gitea response ${response.status}: ${text}`);

  return {
    status: response.status,
    success: response.status >= 200 && response.status < 300,
    url,
    eventType
  };
}
